class Solution(object):
    def minRectanglesToCoverPoints(self, points, w):
        xs = sorted(p[0] for p in points)
        count = 0
        i = 0
        while i < len(xs):
            x0 = xs[i]
            count += 1
            while i < len(xs) and xs[i] <= x0 + w:
                i += 1
        return count
